/**
 * Verify Square webhook signature
 * - Uses HMAC-SHA1
 * - Compares against Square-Signature header
 * - Fails fast if invalid
 */

const crypto = require("crypto");

// 1️⃣ Configuration
const signatureKey = $env.SQUARE_WEBHOOK_SIGNATURE_KEY;

// EXACT webhook URL registered in Square dashboard
// Must match character-for-character (including https, path, no trailing slash changes)
const webhookUrl = "https://https://mod1.app.n8n.cloud/webhook/square-refund";

// 2️⃣ Inputs
const body = JSON.stringify($json);
const signatureHeader =
  $headers["square-signature"] ||
  $headers["Square-Signature"];

if (!signatureHeader) {
  throw new Error("Missing Square-Signature header");
}

// 3️⃣ Construct signed payload
const payload = webhookUrl + body;

// 4️⃣ Compute HMAC
const hmac = crypto
  .createHmac("sha1", signatureKey)
  .update(payload)
  .digest("base64");

// 5️⃣ Timing-safe comparison
const valid = crypto.timingSafeEqual(
  Buffer.from(hmac),
  Buffer.from(signatureHeader)
);

if (!valid) {
  throw new Error("Invalid Square webhook signature");
}

// ✅ Signature valid — pass through unchanged
return [{ json: $json }];

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

/**
 * Normalize Square refund or void into a canonical resolution object.
 * Handles:
 * - refund.status === COMPLETED
 * - payment.status === CANCELED (void)
 */

const root = $json?.data?.object || {};
const now = new Date().toISOString();

// ---- REFUND CASE ----
if (root.refund && root.refund.status === 'COMPLETED') {
  const refund = root.refund;

  return [{
    json: {
      resolution_type: 'REFUND',
      square_payment_id: refund.payment_id,
      square_order_id: refund.order_id || '', // may exist depending on Square version
      square_refund_id: refund.id,
      refund_amount_cents: Number(refund.amount_money?.amount || 0),
      refund_currency: refund.amount_money?.currency || 'USD',
      resolution_at: now,
    }
  }];
}

// ---- VOID CASE ----
if (root.payment && root.payment.status === 'CANCELED') {
  const payment = root.payment;

  return [{
    json: {
      resolution_type: 'VOID',
      square_payment_id: payment.id,
      square_order_id: payment.order_id,
      square_refund_id: '',
      refund_amount_cents: 0,
      refund_currency: payment.amount_money?.currency || 'USD',
      resolution_at: now,
    }
  }];
}

// ---- SHOULD NEVER REACH HERE (guarded upstream) ----
throw new Error('Normalize refund/void: unexpected Square payload');

